const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');

const app = express();

// ---------------------------------------------------------------------------
// Security middleware
// ---------------------------------------------------------------------------

// Set secure HTTP headers (X-Content-Type-Options, HSTS, etc.)
app.use(helmet());

// CORS – restrict to known origins in production
app.use(
  cors({
    origin: process.env.ALLOWED_ORIGINS
      ? process.env.ALLOWED_ORIGINS.split(',')
      : '*',
  })
);

// Body parsers with size limits to prevent large-payload DoS
app.use(express.json({ limit: '1mb' }));
app.use(express.urlencoded({ extended: false, limit: '1mb' }));

// Global rate limiter – 100 requests per 15 minutes per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Remove the X-Powered-By header so the tech stack is not disclosed
app.disable('x-powered-by');

// ---------------------------------------------------------------------------
// Routes
// ---------------------------------------------------------------------------

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res, next) => {
  try {
    // Validate optional query parameters
    const { limit, offset } = req.query;

    if (limit !== undefined) {
      const parsed = Number(limit);
      if (!Number.isInteger(parsed) || parsed < 1 || parsed > 100) {
        return res
          .status(400)
          .json({ error: 'limit must be an integer between 1 and 100.' });
      }
    }

    if (offset !== undefined) {
      const parsed = Number(offset);
      if (!Number.isInteger(parsed) || parsed < 0) {
        return res
          .status(400)
          .json({ error: 'offset must be a non-negative integer.' });
      }
    }

    // Static data – in production this would come from a validated data source
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    const start = Number(offset) || 0;
    const end = limit ? start + Number(limit) : users.length;

    res.json(users.slice(start, end));
  } catch (err) {
    next(err);
  }
});

// ---------------------------------------------------------------------------
// 404 handler – catch unmatched routes
// ---------------------------------------------------------------------------
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found.' });
});

// ---------------------------------------------------------------------------
// Global error handler – MUST have 4 parameters for Express to recognise it
// ---------------------------------------------------------------------------
// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  // Log the full error internally; never expose stack traces to the client
  console.error(err);

  const statusCode = err.statusCode || 500;
  const message =
    process.env.NODE_ENV === 'production'
      ? 'Internal server error.'
      : err.message;

  res.status(statusCode).json({ error: message });
});

// ---------------------------------------------------------------------------
// Start server
// ---------------------------------------------------------------------------
const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

